@startuml

class Storage {
  - compressor: Compressor
  - encryptor: Encryptor
  - cacheEngine: CacheEngine
  - useCompression: boolean
  - useEncryption: boolean
  - useCache: boolean
}

class Compressor {
  + compress()
}

class Encryptor {
  + encrypt()
}

class CacheEngine {
  + put()
}

Storage --> Compressor
Storage --> Encryptor
Storage --> CacheEngine

@enduml
